// --- Parametri Locali ---
float density = 10.0;  // Quante strisce vuoi
bool vertical = true;  // true = verticali, false = orizzontali

// --- Logica ---

// 1. Scegliamo la coordinata su cui basarci (u o v)
// 'u' e 'v' sono variabili standard disponibili nel tuo shader template
float coord = vertical ? u : v;

// 2. Calcoliamo il pattern alternato
// Moltiplichiamo la coordinata (0.0 -> 1.0) per la densità.
// floor() crea gradini interi (0, 1, 2, 3...)
// mod(..., 2.0) restituisce 0.0 o 1.0 alternati
float pattern = mod(floor(coord * density), 2.0);

// 3. Mixing dei colori
// u_col1 e u_col2 sono gli uniform passati dall'interfaccia (Color 1 e Color 2)
// Se pattern è 0.0 -> restituisce u_col1
// Se pattern è 1.0 -> restituisce u_col2
return mix(u_col1, u_col2, pattern);
